 68→  const setSourceLanguage = useCallback(
 69→    async (id: SourceId, language: AppLanguage): Promise<void> => {
 70→      await sourceRepository.setLanguage(id, language);
 71→      setSources((prev) =>
 72→        prev.map((s) => (s.id === id ? { ...s, language } : s))
 73→      );
 74→    },
 75→    []
 76→  );
 77→
 78→  const renameSource = useCallback(
 79→    async (id: SourceId, newName: string): Promise<void> => {
 80→      await sourceRepository.rename(id, newName);
 81→      setSources((prev) =>
 82→        prev.map((s) => (s.id === id ? { ...s, name: newName.trim() } : s))
 83→      );
 84→    },
 85→    []
 86→  );
 87→
 88→  const deleteSource = useCallback(
 89→    async (id: SourceId): Promise<void> => {
 90→      await sourceRepository.delete(id);
 91→      setSources((prev) => prev.filter((s) => s.id !== id));
 92→    },
 93→    []
 94→  );
