const savePending = useCallback(
  async (photoUri: PhotoUri, source?: SourceId): Promise<Recipe> => {
    const newRecipe = await recipeRepository.savePending(photoUri, source);
    setRecipes((prev) => [newRecipe, ...prev]);
    return newRecipe;
  },
