 51→function shuffle<T>(array: Array<T>): Array<T> {
 52→  const result = [...array];
 53→  for (let i = result.length - 1; i > 0; i--) {
 54→    const j = Math.floor(Math.random() * (i + 1));
 55→    [result[i], result[j]] = [result[j], result[i]];
 56→  }
 57→  return result;
 58→}
 59→
 60→export function ProcessingIndicator(): JSX.Element {
 61→  const { t } = useTranslation();
 62→  const shuffled = useMemo(() => shuffle([...ROTATING_KEYS]), []);
 63→  const [index, setIndex] = useState(-1); // -1 = first message
 64→  const opacity = useRef(new Animated.Value(1)).current;
 65→
 66→  useEffect(() => {
 67→    const interval = setInterval(() => {
 68→      Animated.timing(opacity, {
 69→        toValue: 0,
 70→        duration: FADE_DURATION_MS,
 71→        useNativeDriver: true,
 72→      }).start(() => {
 73→        setIndex((prev) => {
 74→          const next = prev + 1;
 75→          return next >= shuffled.length ? 0 : next;
 76→        });
 77→        Animated.timing(opacity, {
 78→          toValue: 1,
 79→          duration: FADE_DURATION_MS,
 80→          useNativeDriver: true,
 81→        }).start();
 82→      });
 83→    }, INTERVAL_MS);
 84→
 85→    return () => clearInterval(interval);
 86→  }, [opacity, shuffled.length]);
 87→
 88→  const key = index < 0 ? "first" : shuffled[index];
 89→  const message = t(`processing.messages.${key}`);
 90→
 91→  return (
 92→    <View style={styles.container}>
 93→      <VignetteOverlay />
 94→      <ActivityIndicator size="large" color="white" />
 95→      <Animated.Text style={[styles.text, { opacity }]}>{message}</Animated.Text>
 96→    </View>
 97→  );
 98→}
