15→const SHOW_COLLAPSE_DURATION_MS = 500;
16→const HIDE_VISUAL_SPRING_CONFIG = {
17→  damping: 28,
18→  stiffness: 220,
19→  mass: 0.55,
20→  overshootClamping: true,
21→} as const;
22→const SHOW_VISUAL_SPRING_CONFIG = {
