181→  var fontSize: CGFloat
182→  var containerSize: CGFloat
183→  var tintColor: UIColor?
184→  var fillColor: UIColor?
185→  var fillProgress: CGFloat
186→  var onPress: () -> Void
187→
188→  private var resolvedFillColor: Color {
189→    if let fillColor = fillColor {
190→      return Color(fillColor)
191→    }
192→    if let tintColor = tintColor {
193→      return Color(tintColor)
194→    }
195→    return Color.blue
196→  }
